        assert_eq!(Props::new(), Props);
    }

    #[test]
    fn module_reexports_allocator_context_type() {
        reset_z_index(Z_INDEX_BASE);

        let allocator = ZIndexAllocator::new();

        assert_eq!(allocator.allocate(), Z_INDEX_BASE);
    }

    #[test]
